import java.util.HashMap;
import java.util.Map;

public class MainActivity extends AppCompatActivity {
    private WebView webView;
    private static final int LOCATION_PERMISSION_REQUEST_CODE = 1001;
    private static final int CAMERA_PERMISSION_REQUEST_CODE = 1002;
    private LocationManager locationManager;
    private LocationListener locationListener;
    private Map<String, Object> pendingRequests = new HashMap<>();

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);
        
        webView = findViewById(R.id.webview);
        locationManager = (LocationManager) getSystemService(Context.LOCATION_SERVICE);
        
        setupWebView();
        setupJavaScriptBridge();
    }

    private void setupWebView() {
        WebSettings webSettings = webView.getSettings();
        webSettings.setJavaScriptEnabled(true);
        webSettings.setDomStorageEnabled(true);
        webSettings.setDatabaseEnabled(true);
        webSettings.setCacheMode(WebSettings.LOAD_DEFAULT);
        webSettings.setAppCacheEnabled(true);
        webSettings.setAllowFileAccess(true);
        webSettings.setAllowContentAccess(true);
        webSettings.setAllowFileAccessFromFileURLs(true);
        webSettings.setAllowUniversalAccessFromFileURLs(true);
        
        webView.setWebViewClient(new WebViewClient() {
            @Override
            public boolean shouldOverrideUrlLoading(WebView view, String url) {
                if (url.startsWith("http://") || url.startsWith("https://")) {
                    return false;
                }
                try {
                    Intent intent = new Intent(Intent.ACTION_VIEW, Uri.parse(url));
                    startActivity(intent);
                } catch (Exception e) {
                    Toast.makeText(MainActivity.this, "Cannot open URL", Toast.LENGTH_SHORT).show();
                }
                return true;
            }
        });
        
        webView.loadUrl("https://your-mobile-website.com");
    }

    private void setupJavaScriptBridge() {
        webView.addJavascriptInterface(new WebAppInterface(this), "AndroidBridge");
    }

    public class WebAppInterface {
        Context mContext;

        WebAppInterface(Context c) {
            mContext = c;
        }

        @JavascriptInterface
        public void getLocation(String callbackId) {
            if (ContextCompat.checkSelfPermission(mContext, Manifest.permission.ACCESS_FINE_LOCATION)
                    == PackageManager.PERMISSION_GRANTED) {
                getLocationData(callbackId);
            } else {
                pendingRequests.put(callbackId, "location");
                ActivityCompat.requestPermissions(MainActivity.this,
                        new String[]{Manifest.permission.ACCESS_FINE_LOCATION},
                        LOCATION_PERMISSION_REQUEST_CODE);
            }
        }

        @JavascriptInterface
        public void openCamera(String callbackId) {
            if (ContextCompat.checkSelfPermission(mContext, Manifest.permission.CAMERA)
                    == PackageManager.PERMISSION_GRANTED) {
                openCameraActivity(callbackId);
            } else {
                pendingRequests.put(callbackId, "camera");
                ActivityCompat.requestPermissions(MainActivity.this,
                        new String[]{Manifest.permission.CAMERA},
                        CAMERA_PERMISSION_REQUEST_CODE);
            }
        }

        @JavascriptInterface
        public void makePayment(String amount, String callbackId) {
            // Implement payment logic here
            try {
                JSONObject result = new JSONObject();
                result.put("status", "success");
                result.put("amount", amount);
                result.put("transactionId", "txn_" + System.currentTimeMillis());
                
                webView.post(() -> webView.loadUrl(
                    "javascript:handlePaymentResult('" + callbackId + "', " + result.toString() + ")"));
            } catch (JSONException e) {
                e.printStackTrace();
            }
        }

        @JavascriptInterface
        public void showToast(String message) {
            runOnUiThread(() -> Toast.makeText(mContext, message, Toast.LENGTH_SHORT).show());
        }

        @JavascriptInterface
        public void shareContent(String title, String text) {
            Intent sendIntent = new Intent();
            sendIntent.setAction(Intent.ACTION_SEND);
            sendIntent.putExtra(Intent.EXTRA_TEXT, text);
            sendIntent.putExtra(Intent.EXTRA_TITLE, title);
            sendIntent.setType("text/plain");
            startActivity(Intent.createChooser(sendIntent, "Share via"));
        }
    }

    private void getLocationData(String callbackId) {
        try {
            Location location = locationManager.getLastKnownLocation(LocationManager.GPS_PROVIDER);
            if (location != null) {
                JSONObject result = new JSONObject();
                result.put("latitude", location.getLatitude());
                result.put("longitude", location.getLongitude());
                result.put("accuracy", location.getAccuracy());
                result.put("timestamp", location.getTime());
                
                webView.post(() -> webView.loadUrl(
                    "javascript:handleLocationResult('" + callbackId + "', " + result.toString() + ")"));
            } else {
                webView.post(() -> webView.loadUrl(
                    "javascript:handleLocationResult('" + callbackId + "', null)"));
            }
        } catch (Exception e) {
            e.printStackTrace();
            webView.post(() -> webView.loadUrl(
                "javascript:handleLocationResult('" + callbackId + "', null)"));
        }
    }

    private void openCameraActivity(String callbackId) {
        // Implement camera intent logic
        webView.post(() -> webView.loadUrl(
            "javascript:handleCameraResult('" + callbackId + "', 'camera_opened')"));
    }

    @Override
    public void onRequestPermissionsResult(int requestCode, @NonNull String[] permissions,
                                         @NonNull int[] grantResults) {
        super.onRequestPermissionsResult(requestCode, permissions, grantResults);
        
        String requestType = pendingRequests.get(String.valueOf(requestCode)) != null ?
                pendingRequests.get(String.valueOf(requestCode)).toString() : "";
        
        if (requestCode == LOCATION_PERMISSION_REQUEST_CODE) {
            if (grantResults.length > 0 && grantResults[0] == PackageManager.PERMISSION_GRANTED) {
                // Permission granted, get location
                String callbackId = "location_callback";
                getLocationData(callbackId);
            } else {
                webView.post(() -> webView.loadUrl(
                    "javascript:handlePermissionDenied('location')"));
            }
        } else if (requestCode == CAMERA_PERMISSION_REQUEST_CODE) {
            if (grantResults.length > 0 && grantResults[0] == PackageManager.PERMISSION_GRANTED) {
                // Permission granted, open camera
                String callbackId = "camera_callback";
                openCameraActivity(callbackId);
            } else {
                webView.post(() -> webView.loadUrl(
                    "javascript:handlePermissionDenied('camera')"));
            }
        }
        
        pendingRequests.remove(String.valueOf(requestCode));
    }

    @Override
    protected void onDestroy() {
        super.onDestroy();
        if (webView != null) {
            webView.destroy();
        }
    }
}